mapper.select:
SELECT h.id, h.address, h.town_street, h.building, h.unit, h.room_no, h.latitude, h.longitude, h.total_floors, h.total_rooms, h.overall_level, h.status, m.manager_name, m.phone as manager_phone, g.grid_name, (SELECT COUNT(*) FROM rental_residents r WHERE r.house_id = h.id AND r.status = '0') as occupied_rooms, (SELECT COUNT(*) FROM rental_residents r WHERE r.house_id = h.id AND r.status = '0') as resident_count, 0 as left_count, h.total_rooms - (SELECT COUNT(*) FROM rental_residents r WHERE r.house_id = h.id AND r.status = '0') as vacant_rooms FROM rental_houses h LEFT JOIN rental_managers m ON h.manager_id = m.id LEFT JOIN rental_grids g ON h.grid_id = g.id WHERE h.latitude IS NOT NULL AND h.longitude IS NOT NULL
AND h.id = #{houseId}
ORDER BY h.create_time DESC

SELECT d.id, d.device_code, d.device_name, d.device_type, d.latitude, d.longitude, d.location, d.status FROM rental_devices d WHERE d.latitude IS NOT NULL AND d.longitude IS NOT NULL
AND d.id = #{deviceId}
ORDER BY d.create_time DESC

SELECT a.id, a.house_id, h.address as house_address, a.alert_type, a.level, a.status, a.description, a.photo_url, h.latitude, h.longitude FROM rental_alerts a LEFT JOIN rental_houses h ON a.house_id = h.id WHERE h.latitude IS NOT NULL AND h.longitude IS NOT NULL
AND a.id = #{alertId}
ORDER BY a.create_time DESC
